-- Enable UUID extension\ncreate extension if not exists \"uuid-ossp\";\n\n-- Auth users (Supabase manages this)\n-- We'll reference auth.users in our tables\n\n-- Projects table\ncreate table if not exists projects (\n  id uuid primary key default uuid_generate_v4(),\n  user_id uuid not null references auth.users(id) on delete cascade,\n  title text not null,\n  description text,\n  genre text,\n  pen_name text,\n  voice_guide text,\n  created_at timestamp with time zone default now(),\n  updated_at timestamp with time zone default now()\n);\n\n-- Chapters table\ncreate table if not exists chapters (\n  id uuid primary key default uuid_generate_v4(),\n  project_id uuid not null references projects(id) on delete cascade,\n  title text not null,\n  section_number integer,\n  chapter_number integer,\n  content text,\n  word_count integer default 0,\n  voice_notes text,\n  order_index integer default 0,\n  created_at timestamp with time zone default now(),\n  updated_at timestamp with time zone default now()\n);\n\n-- Assets table\ncreate table if not exists assets (\n  id uuid primary key default uuid_generate_v4(),\n  project_id uuid not null references projects(id) on delete cascade,\n  name text not null,\n  type text not null check (type in ('image', 'graphic', 'reference', 'style_guide')),\n  url text not null,\n  alt_text text,\n  metadata jsonb,\n  created_at timestamp with time zone default now()\n);\n\n-- Cover Designs table\ncreate table if not exists cover_designs (\n  id uuid primary key default uuid_generate_v4(),\n  project_id uuid not null references projects(id) on delete cascade,\n  title text not null,\n  specification text not null,\n  design_data jsonb not null,\n  image_url text,\n  created_at timestamp with time zone default now(),\n  updated_at timestamp with time zone default now()\n);\n\n-- Style Guides table\ncreate table if not exists style_guides (\n  id uuid primary key default uuid_generate_v4(),\n  project_id uuid not null references projects(id) on delete cascade,\n  voice_instructions text not null,\n  tone_examples text[],\n  formatting_rules jsonb,\n  pen_name text,\n  created_at timestamp with time zone default now(),\n  updated_at timestamp with time zone default now()\n);\n\n-- Version History table\ncreate table if not exists version_history (\n  id uuid primary key default uuid_generate_v4(),\n  chapter_id uuid not null references chapters(id) on delete cascade,\n  content text not null,\n  version_number integer not null,\n  created_at timestamp with time zone default now()\n);\n\n-- Export Jobs table\ncreate table if not exists export_jobs (\n  id uuid primary key default uuid_generate_v4(),\n  project_id uuid not null references projects(id) on delete cascade,\n  format text not null check (format in ('pdf', 'docx', 'epub', 'kdp_print')),\n  status text not null default 'pending' check (status in ('pending', 'processing', 'completed', 'failed')),\n  file_url text,\n  error_message text,\n  created_at timestamp with time zone default now(),\n  updated_at timestamp with time zone default now()\n);\n\n-- AI Content History table\ncreate table if not exists ai_content_history (\n  id uuid primary key default uuid_generate_v4(),\n  project_id uuid not null references projects(id) on delete cascade,\n  content_type text not null check (content_type in ('text', 'image', 'outline', 'caption', 'cover_concept')),\n  prompt text not null,\n  generated_content text,\n  approved boolean default false,\n  created_at timestamp with time zone default now()\n);\n\n-- Indexes for better performance\ncreate index idx_projects_user_id on projects(user_id);\ncreate index idx_chapters_project_id on chapters(project_id);\ncreate index idx_chapters_order on chapters(project_id, order_index);\ncreate index idx_assets_project_id on assets(project_id);\ncreate index idx_cover_designs_project_id on cover_designs(project_id);\ncreate index idx_style_guides_project_id on style_guides(project_id);\ncreate index idx_export_jobs_project_id on export_jobs(project_id);\ncreate index idx_ai_content_history_project_id on ai_content_history(project_id);\ncreate index idx_version_history_chapter_id on version_history(chapter_id);\n\n-- Enable RLS (Row Level Security)\nalter table projects enable row level security;\nalter table chapters enable row level security;\nalter table assets enable row level security;\nalter table cover_designs enable row level security;\nalter table style_guides enable row level security;\nalter table version_history enable row level security;\nalter table export_jobs enable row level security;\nalter table ai_content_history enable row level security;\n\n-- RLS Policies for Projects\ncreate policy \"Users can view their own projects\"\n  on projects for select\n  using (auth.uid() = user_id);\n\ncreate policy \"Users can create projects\"\n  on projects for insert\n  with check (auth.uid() = user_id);\n\ncreate policy \"Users can update their own projects\"\n  on projects for update\n  using (auth.uid() = user_id)\n  with check (auth.uid() = user_id);\n\ncreate policy \"Users can delete their own projects\"\n  on projects for delete\n  using (auth.uid() = user_id);\n\n-- RLS Policies for Chapters (through project ownership)\ncreate policy \"Users can view chapters from their projects\"\n  on chapters for select\n  using (\n    exists (\n      select 1 from projects where projects.id = chapters.project_id and projects.user_id = auth.uid()\n    )\n  );\n\ncreate policy \"Users can create chapters in their projects\"\n  on chapters for insert\n  with check (\n    exists (\n      select 1 from projects where projects.id = project_id and projects.user_id = auth.uid()\n    )\n  );\n\ncreate policy \"Users can update chapters in their projects\"\n  on chapters for update\n  using (\n    exists (\n      select 1 from projects where projects.id = chapters.project_id and projects.user_id = auth.uid()\n    )\n  )\n  with check (\n    exists (\n      select 1 from projects where projects.id = chapters.project_id and projects.user_id = auth.uid()\n    )\n  );\n\ncreate policy \"Users can delete chapters in their projects\"\n  on chapters for delete\n  using (\n    exists (\n      select 1 from projects where projects.id = chapters.project_id and projects.user_id = auth.uid()\n    )\n  );\n\n-- RLS Policies for Assets\ncreate policy \"Users can view assets from their projects\"\n  on assets for select\n  using (\n    exists (\n      select 1 from projects where projects.id = assets.project_id and projects.user_id = auth.uid()\n    )\n  );\n\ncreate policy \"Users can create assets in their projects\"\n  on assets for insert\n  with check (\n    exists (\n      select 1 from projects where projects.id = project_id and projects.user_id = auth.uid()\n    )\n  );\n\ncreate policy \"Users can delete assets in their projects\"\n  on assets for delete\n  using (\n    exists (\n      select 1 from projects where projects.id = assets.project_id and projects.user_id = auth.uid()\n    )\n  );\n\n-- RLS Policies for Cover Designs\ncreate policy \"Users can view covers from their projects\"\n  on cover_designs for select\n  using (\n    exists (\n      select 1 from projects where projects.id = cover_designs.project_id and projects.user_id = auth.uid()\n    )\n  );\n\ncreate policy \"Users can create covers in their projects\"\n  on cover_designs for insert\n  with check (\n    exists (\n      select 1 from projects where projects.id = project_id and projects.user_id = auth.uid()\n    )\n  );\n\ncreate policy \"Users can update covers in their projects\"\n  on cover_designs for update\n  using (\n    exists (\n      select 1 from projects where projects.id = cover_designs.project_id and projects.user_id = auth.uid()\n    )\n  )\n  with check (\n    exists (\n      select 1 from projects where projects.id = cover_designs.project_id and projects.user_id = auth.uid()\n    )\n  );\n\ncreate policy \"Users can delete covers in their projects\"\n  on cover_designs for delete\n  using (\n    exists (\n      select 1 from projects where projects.id = cover_designs.project_id and projects.user_id = auth.uid()\n    )\n  );\n\n-- RLS Policies for Style Guides\ncreate policy \"Users can view style guides from their projects\"\n  on style_guides for select\n  using (\n    exists (\n      select 1 from projects where projects.id = style_guides.project_id and projects.user_id = auth.uid()\n    )\n  );\n\ncreate policy \"Users can create style guides in their projects\"\n  on style_guides for insert\n  with check (\n    exists (\n      select 1 from projects where projects.id = project_id and projects.user_id = auth.uid()\n    )\n  );\n\ncreate policy \"Users can update style guides in their projects\"\n  on style_guides for update\n  using (\n    exists (\n      select 1 from projects where projects.id = style_guides.project_id and projects.user_id = auth.uid()\n    )\n  )\n  with check (\n    exists (\n      select 1 from projects where projects.id = style_guides.project_id and projects.user_id = auth.uid()\n    )\n  );\n\n-- RLS Policies for Version History\ncreate policy \"Users can view version history for their chapters\"\n  on version_history for select\n  using (\n    exists (\n      select 1 from chapters c\n      join projects p on p.id = c.project_id\n      where c.id = version_history.chapter_id and p.user_id = auth.uid()\n    )\n  );\n\ncreate policy \"Users can create versions for their chapters\"\n  on version_history for insert\n  with check (\n    exists (\n      select 1 from chapters c\n      join projects p on p.id = c.project_id\n      where c.id = chapter_id and p.user_id = auth.uid()\n    )\n  );\n\n-- RLS Policies for Export Jobs\ncreate policy \"Users can view exports from their projects\"\n  on export_jobs for select\n  using (\n    exists (\n      select 1 from projects where projects.id = export_jobs.project_id and projects.user_id = auth.uid()\n    )\n  );\n\ncreate policy \"Users can create exports for their projects\"\n  on export_jobs for insert\n  with check (\n    exists (\n      select 1 from projects where projects.id = project_id and projects.user_id = auth.uid()\n    )\n  );\n\n-- RLS Policies for AI Content History\ncreate policy \"Users can view AI content from their projects\"\n  on ai_content_history for select\n  using (\n    exists (\n      select 1 from projects where projects.id = ai_content_history.project_id and projects.user_id = auth.uid()\n    )\n  );\n\ncreate policy \"Users can create AI content in their projects\"\n  on ai_content_history for insert\n  with check (\n    exists (\n      select 1 from projects where projects.id = project_id and projects.user_id = auth.uid()\n    )\n  );\n